# ===================================================================
# Lumber Buddy Phase 1 — Artifact Panel
# Paste this whole block into PowerShell from C:\Users\garre\Desktop\musser-biomass-ops
# ===================================================================
$ErrorActionPreference = 'Stop'
if (-not (Test-Path 'index.html') -or -not (Test-Path 'api/claude.js')) {
  Write-Host "ERROR: run from the musser-biomass-ops folder" -ForegroundColor Red; return
}
Copy-Item index.html index.html.bak -Force
Copy-Item api/claude.js api/claude.js.bak -Force
Write-Host "Backups saved." -ForegroundColor DarkGray

$html_b64 = ''
$js_b64 = ''

[IO.File]::WriteAllBytes((Resolve-Path '.').Path + '\index.html', [Convert]::FromBase64String($html_b64))
[IO.File]::WriteAllBytes((Resolve-Path '.').Path + '\api\claude.js', [Convert]::FromBase64String($js_b64))

Write-Host ""
Write-Host "✓ index.html written ($([IO.File]::ReadAllBytes('index.html').Length) bytes)" -ForegroundColor Green
Write-Host "✓ api/claude.js written ($([IO.File]::ReadAllBytes('api/claude.js').Length) bytes)" -ForegroundColor Green
Write-Host ""
Write-Host "Now run:" -ForegroundColor Yellow
Write-Host "  git add ." -ForegroundColor Cyan
Write-Host "  git commit -m 'feat: phase 1 artifact panel — HTML mockups stream live next to chat'" -ForegroundColor Cyan
Write-Host "  git push" -ForegroundColor Cyan
